	}
	_, err, _ = m.singleflight.Do(key, func() (interface{}, error) {
		return nil, m.BaseHandler.CallResource(ctx, req, sender)
	})
	if err != nil {
		return fmt.Errorf("request deduplication middleware: calling BaseHandler.CallResource: %w", err)
	}
	return nil
}

